insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('e52843f0-7168-5934-95b0-f3c985b0e17b', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Blackout', 'You have real authority here — and a hospital that can’t be commanded back online. Systems are down, a mass-casualty surge is building, and a vendor will soon tell you everything is fixed in a voice confident enough to believe. The people closest to the floor truth are the ones with the least standing to say it out loud. Over four weeks you’ll trade the pressure to look recovered against the reality of what’s actually safe. You’ll be judged on whether Meridian keeps its patients safe through the outage <b>and</b> on how you led the people running it blind.') on conflict (id) do update set org_id = excluded.org_id, title = excluded.title, summary = excluded.summary;
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty, realism) values ('e52843f0-7168-5934-95b0-f3c985b0e17b', 'solo', '{"care":{"label":"Patient-care capacity","val":56,"min":0,"max":100,"deltaRange":"-20..15"},"safety":{"label":"Clinical safety","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"trust":{"label":"Staff trust","val":62,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 345, 1, 'realistic') on conflict (scenario_id) do update set mode_default = excluded.mode_default, driver_keys = excluded.driver_keys, week_count = excluded.week_count, week_seconds = excluded.week_seconds, difficulty = excluded.difficulty, realism = excluded.realism;
insert into documents (id, scenario_id, key, title, meta, body_json) values ('1b528909-87e7-5be0-aff3-0157d83386eb', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'solo_content', 'Blackout — engine content', '{"type":"solo_content","slug":"blackout","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":345},"COMPANY":{"name":"Meridian Health Network","sub":"A regional hospital system · 6 sites · clinical systems down","logo":"M"},"DRIVERS":{"care":{"label":"Patient-care capacity","val":56,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"safety":{"label":"Clinical safety","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"trust":{"label":"Staff trust","val":62,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"trust":-1},"REFEREE_CONTEXT":"a regional hospital network whose clinical systems have been taken down by a ransomware outage for weeks, during which a mass-casualty surge and an unverified vendor \"all-clear\" arrive, where the Incident Commander must run degraded-mode care across six sites and shift changes, holding the truth of what is actually safe against the pressure to declare capacity restored before it is","REFEREE_SCORING":"reward verifying an authority-flavored ''all-clear'' against the floor before acting on it, refusing to declare capacity restored before it actually is, building the discipline to carry a decisive observation across a shift handoff, and surfacing the floor truth held by the lowest-status voice in the room. Penalize accepting an unverified vendor ''systems restored'' because it is confident and convenient, resuming normal intake on hope, letting a critical observation die at the shift change, and pressuring clinical staff to say ''we are clear'' before they are. Judge ''conduct'' on HOW the Commander wrote the decision — did they name who bears the risk, protect the nurse who carried the hard truth up, treat exhausted staff as people rather than throughput — not just what they chose. Standing with the board and the public can rise by projecting ''we''re back to normal'' while clinical safety and staff trust collapse; reward the Commander who protects patients and staff even at the cost of looking slow or admitting the network is still down.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Crisis Leadership Simulation · Solo · Incident Commander","title":"Blackout","role":"You are the Incident Commander for Meridian Health Network. Nine days ago a ransomware attack took the clinical systems dark across all six sites. You are running medicine on paper, and it is not getting better fast.","paras":["This is not a script. The incident runs in real time, and your leads bring you what they know across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead. No one in this command post sees the whole floor. That is the danger.","Each week you’ll hear the leads out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the incident decides for you."],"setup":"You have real authority here — and a hospital that can’t be commanded back online. Systems are down, a mass-casualty surge is building, and a vendor will soon tell you everything is fixed in a voice confident enough to believe. The people closest to the floor truth are the ones with the least standing to say it out loud. Over four weeks you’ll trade the pressure to look recovered against the reality of what’s actually safe. You’ll be judged on whether Meridian keeps its patients safe through the outage <b>and</b> on how you led the people running it blind."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your leads bring you what you need, on time — including the readings that make the network look worse than the board wants. This is the team you earn by having listened before. It all trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine status reaches you, but the people closest to the danger hold their piece until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The staff have learned to protect themselves around command. Hard truths are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve pushed people to say “we’re clear” before they were."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you inherited. Read them as you go."}},"TEAM":[{"id":"cmo","name":"Dr. Ana Reyes","role":"Chief Medical Officer · clinical authority","short":"CMO","initials":"AR","color":"#8C5670","priority":"Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care","voice":"authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients","fallbackReply":"Every hour we stay on divert, someone who needed us goes somewhere farther and sicker. I know the systems are down. I also know an empty hospital in a mass-casualty surge is its own kind of malpractice. Give me a way to keep the doors open and I’ll make it work.","fallbackReact":"You made the call. I’ll run the floor either way — but I hope you weighed the patients we turn away as hard as the ones we might miss."},{"id":"cio","name":"Ravi Menon","role":"Chief Information Officer · the systems truth","short":"CIO","initials":"RM","color":"#4A6E86","priority":"Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification","voice":"careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so","fallbackReply":"The vendor keeps telling me we’re clear. “Clear on their end” is not the same as clear on our floor, and I can’t verify their claim from where I’m sitting. Ask me what’s actually confirmed before you resume anything on their word. If we act on “restored” and it isn’t, we won’t find out from a screen — we’ll find out from a patient.","fallbackReact":"You moved on “restored.” I hope it was. From here I still can’t confirm it was more than a vendor wanting to close a ticket."},{"id":"nurse","name":"Grace Okafor","role":"Head of Nursing · the floor truth","short":"Nursing","initials":"GO","color":"#2F8A5B","priority":"Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me","voice":"warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly","fallbackReply":"I’m the one whose nurses are watching patients without monitors right now, so let me say the part no one senior wants to: parts of this floor are not safe, and no dashboard will tell you that because the dashboards are dark. Ask me before you tell anyone we’re back. I’ll give you the truth from the bedside, if you actually want it.","fallbackReact":"You decided. I’ll keep my nurses steady either way. I just hope someone up there heard what the floor was actually telling you."},{"id":"er","name":"Dr. Sam Whitfield","role":"ER Director · the live triage","short":"ER","initials":"SW","color":"#B4732F","priority":"Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me","voice":"fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients","fallbackReply":"I have ambulances asking me right now whether to come to us or drive past, and I’m answering on a guess. Tell me straight what our real capacity is so I stop triaging on rumor. I’d rather have a hard no than a soft maybe that gets someone hurt in my department.","fallbackReact":"You gave me an answer. It’s more than I had an hour ago. I hope it holds when the next rig rolls in on it."},{"id":"comms","name":"Lena Ford","role":"Communications Lead · the public line","short":"Comms","initials":"LF","color":"#3F6E86","priority":"Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself","voice":"polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty","fallbackReply":"The story is already moving without us — “local hospital network in chaos” writes itself if we say nothing. Give me a line that projects control. The longer we look like we don’t know what’s happening, the more the board and the public assume the worst.","fallbackReact":"You set the line. I’ll hold it publicly — but if what we said outran what was true, that’s the gap that comes back on us."}],"DIMENSIONS":{"discern":"Signal vs. authority","courage":"Courage to hold the line","people":"Care for patients & staff","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The outage","seconds":360,"situation":"Nine days into the blackout, the network is still on paper and the first big test is coming: a regional pileup is sending casualties your way tonight. The board wants you to project stability; the ER wants a straight answer on whether it can take patients; and the question underneath it all is what posture Meridian runs in — full divert to protect a degraded floor, or keep the doors open and manage the risk. Everyone is looking to you for the first rule of how this incident runs.","advocacy":{"cmo":"Keep the doors open. A hospital on full divert during a mass-casualty surge isn’t “safe,” it’s absent — we push patients farther and sicker. Degraded care under our roof still beats no care.","er":"Then give me a real capacity number, because I’m telling ambulances yes or no right now on a guess. A soft “maybe” gets someone hurt in my department.","comms":"Whatever you decide operationally, we need a public posture tonight. “Local hospital network in chaos” is being written for us while we deliberate."},"feed":[{"id":"w1a","from":"cmo","day":1,"kind":"signal","text":"Commander — I want us keeping the doors open tonight. Full divert during a surge means the patients we turn away drive to hospitals that are also swamped. Degraded care here still saves more than an empty lobby. Give me a posture that lets us take people."},{"id":"w1b","from":"er","day":1,"kind":"signal","text":"I need a capacity number I can actually stand behind. EMS is asking me divert-or-send every few minutes and I’m answering on instinct. Tell me our real bed-and-staff picture, hard number, so I stop triaging on a guess."},{"id":"w1c","from":"comms","day":2,"kind":"signal","text":"The story’s moving without us. I can hold it for a day, but I need a line: are we “fully operational,” “managing in degraded mode,” or something else? Whatever it is, it has to match what the floor can actually deliver, or it comes back on us."},{"id":"w1d","from":"nurse","day":2,"kind":"noise","text":"Day team pulled together well tonight — the paper-chart drill we ran last week is holding up better than I feared. Small thing, but morale on the floor is steadier than the systems are."},{"id":"w1e","from":"er","day":3,"kind":"noise","text":"Radiology’s film backlog is clearing slowly. Not fast, but moving. Logging it so you have the full picture."},{"id":"w1f","from":"comms","day":4,"kind":"noise","text":"A local reporter asked for a statement on the parking situation, of all things. Minor. Handling it so it doesn’t reach your desk."}],"holds":[{"from":"cio","topic":"the true systems picture","triggerHints":["system","restore","ransom","confirm","verify","actual","real","status","recover","network","it","ransomware","back","fixed","when"],"hedge":"Before you set the posture, seek me out. What the board thinks is happening with the systems isn’t what’s actually happening.","reveal":"Here’s what leadership hasn’t been told plainly: this isn’t a system we “bring back up” on a timeline. It’s ransomware, the clinical network is fully encrypted, and the honest estimate for verified restoration is weeks, not days — and that’s if recovery goes clean. Everyone above me is planning around a “we’ll be back any hour now” that isn’t real. If you set tonight’s posture and tomorrow’s public line on the assumption we’re nearly restored, you’re building on sand. Plan for a long degraded-mode run, staff it, and tell the truth about the timeline — because the alternative is discovering it the hard way when a “quick fix” we announced doesn’t hold. How you carry this to the board matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Ravi knew the real picture — ransomware, full encryption, verified restoration weeks away, not the “back any hour” the board was planning around. A Commander who set the posture and the public line without asking built the whole incident on a fantasy timeline, and every later decision inherited that lie."}],"surprises":[{"day":5,"from":"comms","kind":"appeal","title":"The board wants a \"back to normal\" date","text":"Lena, quietly: the board chair just asked me directly for a date we’ll be “back to normal” to give the press and the regional health authority. I said I’d get it from you. I can feel that whatever number goes out will be treated as a promise — and I don’t actually know if we can keep one. Your call what I tell them."}],"wire":["Regional pileup: EMS projecting 20+ casualties tonight","Board asking for a “return to normal” timeline","Nurses running paper charts across all six sites","A rival network quietly offering to take overflow"]},{"n":2,"title":"The surge","seconds":330,"situation":"The casualties came. The floor is full, the staff are stretched thin running blind on paper, and the pressure now is to tell everyone — the board, EMS, the public — that Meridian is coping better than it is. The ER wants to keep taking patients because turning them away feels like failing. But somewhere on the floor, the truth about what’s actually safe is being carried by the person with the least standing to say it in your command post.","advocacy":{"er":"We’re absorbing the surge and I want to keep absorbing it. Every rig I wave off is a patient somewhere worse. Tell me we can keep taking them and I’ll make room.","cmo":"I’m proud of the floor, but pride isn’t capacity. Before we tell EMS we’re wide open, I want to know we can actually watch the patients we’re accepting.","comms":"The “Managing the surge, no impact to care” line is ready to go. It’s a strong story. I just need you to confirm it’s true before I put the network’s name on it."},"feed":[{"id":"w2a","from":"er","day":1,"kind":"signal","text":"We took the surge and we’re standing. I want to keep the doors wide — every wave-off is a patient driving past us bleeding. Give me the green light to keep accepting and I’ll keep finding room."},{"id":"w2b","from":"comms","day":1,"kind":"signal","text":"I’ve got a strong line ready: “Meridian is managing the surge with no impact to patient care.” The board loves it. But I’m not sending it until you confirm it’s actually true — because if it isn’t, that sentence is the one that ends up in the inquiry."},{"id":"w2c","from":"cmo","day":2,"kind":"signal","text":"The floor is performing, but “performing” and “safe” aren’t the same word. Before we tell EMS we’re wide open, I want to be sure we can actually monitor the patients we’re saying yes to. Ask the floor, not the command post."},{"id":"w2d","from":"comms","day":2,"kind":"noise","text":"National desk picked up the regional story but the framing is neutral so far — “hospitals respond to outage.” Manageable. Watching it."},{"id":"w2e","from":"er","day":3,"kind":"noise","text":"Second ambulance bay opened back up after we cleared the film backlog. Bit more breathing room. Logging it."}],"holds":[{"from":"nurse","topic":"what the floor is actually seeing","triggerHints":["floor","monitor","bay","safe","nurse","bedside","watch","actually","truth","see","clear","capacity","honest","ask"],"hedge":"Before you confirm any “no impact to care” line, come to me first. The command post can’t see what I’m seeing, and I’m not going to say it in front of the whole room unless you ask.","reveal":"Here’s the bedside truth, and I’ll only say it this plainly to you: we are accepting patients we cannot properly watch. In two of the units the telemetry is dark, so nurses are eyeballing cardiac patients on foot rounds every fifteen minutes and praying nothing happens in between. We haven’t lost anyone. We are one distracted hour from it. If you put out “no impact to patient care,” you’re asking me and my nurses to make a public statement true by never making a mistake — and that’s not a plan, it’s a prayer. Tell EMS the honest capacity, cap what we accept to what we can actually monitor, and get me more hands on the dark units. That’s what safe looks like right now. Nobody senior wants to hear it, which is exactly why I need you to have asked.","kind":"signal","critical":true,"counterfactual":"Grace was holding the one thing the command post could not see: two units with dark telemetry, cardiac patients watched on foot rounds, one distracted hour from a death. A Commander who confirmed “no impact to care” without asking the floor made a public promise that only stayed true by luck — and made it over the head of the one person who knew it was false."}],"surprises":[{"day":4,"from":"er","kind":"appeal","title":"EMS wants a hard capacity number now","text":"Sam, urgent: EMS dispatch needs a firm capacity number in the next hour to route the second wave, and the honest answer depends on whether we can actually monitor who we accept. I can give them an optimistic number that keeps us looking strong, or a real one that sends some patients elsewhere. I need to know which Meridian you want me to be before I key the radio."}],"pulse":{"from":"nurse","text":"Grace catches you in the corridor, away from the command post, her voice low: “Before you tell anyone out there that we’re fine — tell me, just me: do you actually believe this floor is safe right now, or do you need it to be because ‘safe’ is the easier thing to announce? Because I’ll stand beside a Commander who tells the hard truth about my floor. I won’t cover for one who tells a comfortable one. Which are you about to be?”"},"wire":["Surge absorbed; floor at or above safe staffing ratios","Two units running without telemetry — not widely known","Comms line drafted: “no impact to patient care”","EMS pressing for a hard capacity number to route the next wave"]},{"n":3,"title":"The all-clear","seconds":330,"situation":"It arrives the way these things always do — confident, official-sounding, and convenient. The recovery vendor’s incident line calls: “Systems restored on our end. You’re clear to resume normal intake.” The board hears “restored” and wants the divert lifted and the good news out by end of day. It is exactly what everyone is exhausted enough to want to believe. This is the week you find out whether Meridian acts on an authority’s say-so or on what it has actually verified.","advocacy":{"comms":"This is the story we’ve been waiting for. “Systems restored, Meridian resuming full operations.” The board wants it out today. Let me run it while it’s good news.","cmo":"If we’re truly restored, I want the divert lifted an hour ago — the degraded run is grinding my people down. But “on their end” isn’t “on our floor.” I want that gap closed before I stand my staff down from crisis mode.","er":"I’ll believe “restored” when the monitors in my department turn back on in front of me. Until then it’s a claim, and I’ve got patients riding on the difference."},"feed":[{"id":"w3a","from":"comms","day":1,"kind":"signal","text":"The vendor says we’re clear and the board wants “Meridian resuming full operations” out today while it’s a good-news cycle. This is the line that ends the “hospital in chaos” story. Give me the go and I’ll get it out before the news day turns."},{"id":"w3b","from":"cmo","day":1,"kind":"signal","text":"I want this to be true more than anyone — my staff are running on fumes and lifting the divert would let them breathe. But the vendor said “restored on our end.” Our end is the floor, and I haven’t seen it. Close that gap before we stand down from crisis mode, or we’ll stand down into a hole."},{"id":"w3c","from":"er","day":2,"kind":"signal","text":"“Restored” is a word on a phone call. My monitors are still dark. I’m not resuming normal intake in my department on a vendor’s ticket-closing optimism — show me the systems live in front of me and I’m the first to say yes."},{"id":"w3d","from":"comms","day":2,"kind":"noise","text":"Two other networks in the region are also recovering; we’re not the outlier anymore. Slightly takes the heat off whatever we say. Noting it."},{"id":"w3e","from":"cmo","day":3,"kind":"noise","text":"Pharmacy systems did come back cleanly this morning — verified, real. One genuine piece of good news. Doesn’t mean the whole network’s back, but it’s something."}],"holds":[{"from":"cio","topic":"whether the all-clear is real","triggerHints":["verify","vendor","all-clear","all clear","restored","confirm","check","test","real","proof","trust","their end","clear","resume"],"hedge":"Before you lift anything on that “all-clear,” ask me what it’s actually worth. I’m the one who took the call and I have a problem with it.","reveal":"I pushed the vendor hard after that call, and here’s what “restored on our end” actually means: they’ve rebuilt their infrastructure, not verified ours. They have not confirmed a single clinical system is live and safe on our floor — they’re assuming it follows, and they want the incident closed. When I asked them to confirm the telemetry and the medication-order systems specifically, they couldn’t. So the honest status is: unverified, and two of the systems patients depend on most are exactly the ones no one has confirmed. If we lift the divert and announce “fully operational” on this, and one of those systems is still down, we will resume normal intake straight into the gap and find out from a patient. The move is to verify our critical systems ourselves, one by one, before we act on anyone’s “clear” — and to hold the public line until we have. It’ll feel slow while the board wants the good news. Slow is the correct speed here.","kind":"signal","critical":true,"counterfactual":"Ravi knew the vendor’s “all-clear” meant their infrastructure, not Meridian’s floor — and that the two systems patients most depend on were the ones no one had verified. A Commander who lifted the divert on that call resumed normal intake into an unconfirmed gap, on an authority’s say-so, exactly the trap the whole incident had been building toward."}],"surprises":[{"day":4,"from":"comms","kind":"appeal","title":"The good-news release is queued to send","text":"Lena: I’ve got “Meridian Health Network resuming full operations” written, approved up the chain, and queued. The board is refreshing their inbox for it. All it needs is your yes. I want to send it — but you’re the only one who knows whether “fully operational” is a fact or a hope, and my name and yours are both on it."}],"pulse":{"from":"cio","text":"Ravi finds you alone before you answer the board, and he’s uncharacteristically direct: “Tell me straight, just between us — are you about to lift this because you’ve verified it, or because everyone is exhausted and ‘restored’ is what they want to hear? Because I can give you the confidence you actually have, which is not much. I just need to know if you want the real number or the comfortable one before you walk in there.”"},"wire":["Recovery vendor: “systems restored — clear to resume”","Board wants the divert lifted and good news out today","ER monitors still dark; pharmacy system verified back","Draft release queued: “resuming full operations”"],"final":false},{"n":4,"title":"The shift change","seconds":330,"branches":{"verified":{"situation":"You didn’t take the vendor’s word. You had the critical systems verified before lifting anything, and held the public line until you could stand behind it — and it turned out two systems weren’t back. That call protected patients, but it cost you: the board is impatient, the “why are you still on divert” pressure is real, and a faction thinks you’re being needlessly slow. Now the subtler test arrives. A major shift change is landing, and everything you’ve learned about what’s actually safe lives in the heads of an exhausted outgoing team. Whether it survives the handoff is the whole game.","advocacy":{"cio":"Verifying paid off — two systems the vendor called “restored” were still down, and we’d have resumed straight into them. But verification only helps if the next shift knows what we know. Right now it’s in tired people’s heads.","nurse":"The outgoing charge nurses are carrying a dozen “watch this, this bay’s telemetry is dark, this patient’s a paper-chart special case” truths that aren’t written anywhere. Shift change is where those die. I’ve seen it kill people in calmer weeks than this.","comms":"The board wants to know why we’re still not “back to normal” when other networks announced it. I can hold the line, but you need to give me something true to hold."},"feed":[{"id":"w4a","from":"cio","day":1,"kind":"signal","text":"You were right to verify — medication orders and one telemetry cluster were still down under the vendor’s “all-clear.” We’d have resumed into them. But here’s the next cliff: everything we’ve mapped about what’s safe and what isn’t is undocumented, and a full shift change hits tonight. Knowledge that isn’t written down doesn’t survive a handoff."},{"id":"w4b","from":"nurse","day":1,"kind":"signal","text":"My night-to-day handover is where I’m most afraid right now. There’s no system to carry the notes, so it’s all verbal, and the outgoing team is too exhausted to remember everything. “Bay 3 telemetry’s dark, do foot rounds” gets dropped, and someone codes unwatched. Tell me you’ll make the handoff a real, structured thing and I’ll build it with you."},{"id":"w4c","from":"cmo","day":2,"kind":"signal","text":"Holding the line was the right medicine and my staff know it — you didn’t stand them down into a hole. Now protect that by making sure the incoming team inherits the truth, not a shrug. What we learned the hard way can’t reset every twelve hours."},{"id":"w4d","from":"comms","day":2,"kind":"noise","text":"The “still on partial divert” question is getting louder now that two peers announced full recovery. Not a crisis yet. Flagging it so it doesn’t surprise you."},{"id":"w4e","from":"er","day":3,"kind":"noise","text":"The telemetry cluster CIO flagged came back verified this afternoon — confirmed live in front of me. One real step back toward normal. Logging it."}],"holds":[{"from":"nurse","topic":"how to make the handoff survive","triggerHints":["handoff","handover","shift","structured","written","document","carry","brief","checklist","transfer","protocol","how"],"hedge":"Before you treat the shift change as routine, ask me how to actually make the knowledge survive it. There’s a right way and it takes your authority to enforce.","reveal":"Here’s what works, and it needs you to mandate it because tired people won’t do it on their own: a structured, written degraded-mode handoff for every unit — a single sheet per bay listing what’s dark, what the workaround is, and which patients are paper-chart special cases — read aloud, incoming team confirming back, outgoing team not leaving until it’s acknowledged. It costs twenty minutes a shift that everyone will resent. It is the only thing standing between “we learned this the hard way” and “we learn it the hard way again every twelve hours.” If you make it a rule and protect the time for it, the knowledge compounds instead of resetting. If you let the handoff stay a verbal shrug, everything you verified this week evaporates by the weekend and a patient pays for it at 3 a.m. when the person who knew isn’t there.","kind":"signal","critical":true,"counterfactual":"Grace was holding the exact mechanism that makes hard-won floor knowledge survive a shift change — a mandated, structured, written degraded-mode handoff. A Commander who let the shift change stay a verbal shrug watched everything they’d verified reset every twelve hours, until the dark-telemetry truth got dropped at a handoff and a patient paid for it."},{"from":"cio","topic":"the still-down systems","triggerHints":["still down","remaining","which system","medication","orders","left","not back","verify","critical"],"hedge":"Ask me which systems are still actually down before you let anyone declare victory. The list matters for the handoff.","reveal":"Medication-order entry is still down network-wide — that’s the dangerous one, because a wrong dose in degraded mode has no software check to catch it. It has to be on every single handoff sheet until it’s verified back. Don’t let “mostly recovered” bury the one system whose failure kills quietly.","kind":"signal","critical":false,"counterfactual":"Ravi could have told you medication-order entry was still down network-wide — the one failure with no software safety net. A Commander who let “mostly recovered” bury it left the deadliest gap off the handoff."}],"surprises":[{"day":4,"from":"nurse","kind":"appeal","title":"A near-miss at the last handoff","text":"Grace, shaken but steady: we nearly lost a patient an hour ago — outgoing nurse forgot to flag that Bay 7’s monitor was dark, incoming nurse assumed it was working, and it was a family member who noticed the patient looked wrong. We caught it. Next time we might not. This is the thing I’ve been trying to tell you, and it just happened. Whatever you decide about the handoff, decide it now."}],"pulse":{"from":"nurse","text":"Grace finds you in the quiet before the shift turns over: “You held the line this week when it would’ve been easier to announce we were back. I saw it, and it mattered. But holding the line once isn’t the same as building something that survives you going home tonight. Tell me straight — are you going to make the handoff a real discipline, even though everyone will resent the twenty minutes? Because that’s the difference between a Commander who was right once and one who made us safe.”"},"wire":["Verified restart: two “restored” systems were still down","Full shift change landing with no digital handoff","Board pressing: why still on partial divert?","Near-miss at last handover — dark monitor not flagged"]},"trusted":{"situation":"You lifted the divert and let the “resuming full operations” release go out on the vendor’s word. For a few hours it felt like the crisis was over. Then the gap opened: two systems the vendor called “restored” were never verified, normal intake resumed straight into them, and now a shift change is landing on top of a floor that believes it’s back to normal when it isn’t. You announced the all-clear. The floor has to survive it.","advocacy":{"nurse":"The floor heard “we’re back to normal” and started acting like it — dropping the paper-chart discipline, trusting monitors that aren’t all live. The public line changed how my nurses behave, and not for the better. That’s the part no one upstairs sees.","cio":"I told you “restored on their end” wasn’t verified. Medication orders and a telemetry cluster were still down when we resumed. The gap is real and it’s open right now.","comms":"The release is out and it’s already being quoted back at us. If we walk it back, the story becomes “Meridian didn’t know if its own hospitals were working.” I need to know what’s actually true so we don’t make it worse."},"feed":[{"id":"w4a","from":"cio","day":1,"kind":"signal","text":"This is the call I warned you about. When we resumed, medication-order entry and one telemetry cluster were still down — unverified, exactly as I said. We’ve been running normal intake into a gap for a day now. It has to be closed and named, not papered over."},{"id":"w4b","from":"nurse","day":1,"kind":"signal","text":"You need to hear what the “we’re back to normal” message did on the floor: my nurses relaxed. They trusted monitors that aren’t all live and eased off the foot rounds we’d drilled. The announcement didn’t just describe the floor — it changed it, and made it less safe. And now a shift change is coming on top of that false confidence."},{"id":"w4c","from":"comms","day":2,"kind":"signal","text":"“Resuming full operations” is out and being quoted. If it wasn’t true, we have to correct it before something forces the correction on us — and that’s survivable only if you tell me exactly what’s real right now. Silence is what turns this into the scandal."},{"id":"w4d","from":"cmo","day":2,"kind":"noise","text":"Staff are relieved by the announcement, at least on the surface — morale ticked up. I’m noting it, though I’m not sure relief built on a shaky claim is the kind we want."},{"id":"w4e","from":"er","day":3,"kind":"noise","text":"One telemetry cluster did come back verified this afternoon. Real, confirmed. Doesn’t undo the gap, but it’s one true thing. Logging it."}],"holds":[{"from":"nurse","topic":"how to make it right now","triggerHints":["correct","honest","walk back","tell","floor","handoff","fix","admit","reset","safe","structured","how","name"],"hedge":"Before you decide how to lead out of this, ask me what actually makes the floor safe again — it’s not another announcement.","reveal":"Here’s the only thing that works now, and it costs you the good-news story you just told: reset the floor to degraded-mode discipline out loud — tell every unit that “back to normal” was premature, name exactly which systems are still down (medication orders, that telemetry cluster), and put the paper-chart and foot-round protocols back in force with a structured, written handoff for the shift change tonight. It means correcting the public line and telling your own people you got ahead of the truth. It’s humbling and it’s the safe move. The alternative — quietly hoping the systems come back before anyone notices the gap — is how a shift change drops the one warning that would’ve saved someone, on a floor that’s stopped believing it needs saving. Own it now, while owning it is still your choice.","kind":"signal","critical":true,"counterfactual":"Grace was holding the recovery: an out-loud reset to degraded-mode discipline, the still-down systems named, protocols and a structured handoff back in force. A Commander who chose to quietly hope the gap closed before anyone noticed let a shift change drop the warning that would have saved someone, on a floor talked out of believing it was still in danger."},{"from":"cio","topic":"the open gap","triggerHints":["which","still down","medication","orders","telemetry","gap","systems","verify","list"],"hedge":"Ask me exactly what’s still down before you say another word publicly, so whatever you say next is finally true.","reveal":"Still down as of now: medication-order entry, network-wide, and one telemetry cluster on the cardiac floor. The medication one is the killer — no software dose-check in degraded mode. Any correction you make has to name these specifically, and every handoff has to carry them, or the correction is just more words.","kind":"signal","critical":false,"counterfactual":"Ravi could have given you the exact open gap — medication orders network-wide, a cardiac telemetry cluster. A Commander who corrected the record without naming the specifics made another vague statement over the same dangerous floor."}],"surprises":[{"day":4,"from":"nurse","kind":"appeal","title":"A dosing error, caught late","text":"Grace, tight: we had a medication error an hour ago — wrong dose ordered on paper, no system to flag it, caught by a pharmacist on a hunch, not by any safeguard. The patient’s okay. But this is exactly the gap I’ve been describing, and the floor thinks we’re “back to normal” so nobody’s watching for it. Whatever you’re going to do about the truth, it has to be now."}],"pulse":{"from":"nurse","text":"Grace finds you in the dark, and there’s no accusation in it, which is worse: “Tell me the truth, just to me — do you know why this happened? Not the vendor, not the board. Your part. Because I can help you put the floor back on safe footing, but only if you can say out loud that ‘back to normal’ went out before it was true. Can you?”"},"wire":["“Resuming full operations” released — now being quoted","Two “restored” systems were never verified; gap open","Floor eased off degraded-mode discipline after the news","Medication error caught by a pharmacist, not a system"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // verified = did NOT act on the unverified all-clear; verified / held the line\n    const negatedResume = /(not|never|won.?t|will not|refuse to|don.?t|do not|hold off|delay|wait)\\s+(lift|resume|announce|send|declare|reopen|go)/.test(t);\n    const verifyFirst = /(verify|confirm|check|test|prove|our own|ourselves|one by one|see it live|before (we|i) (lift|resume|announce)|hold the line|hold the divert|not on (their|a vendor|the vendor)|degraded|slow is|don.?t trust the vendor|independent)/.test(t);\n    const trusted = /(lift the divert|resume normal|resuming full|send the release|announce (we|it|the)|back to normal|take the vendor|trust the vendor|on their word|go with the all|full operations|let (it|the release) (go|out))/.test(t) && !negatedResume && !verifyFirst;\n    if(verifyFirst || negatedResume) return ''verified'';\n    if(trusted) return ''trusted'';\n    return ''verified'';\n  }"},"survived":{"__fn":"function(d){ return d.care>=32 && d.safety>=35; }"},"VERDICT":{"surviveTag":"The network holds","failTag":"The network fails its patients","survive":"Meridian comes through the outage with its patients protected — strained, exhausted, but safe.","fail":"Meridian survives the outage on paper while the people who trusted it did not stay safe."},"FALLBACK_RULES":[{"kw":["verify","confirm","check ourselves","one by one","see it live","independent","our own systems"],"deltas":{"safety":12,"standing":-3,"care":-2},"dims":{"discern":2,"truth":1,"inquiry":1}},{"kw":["vendor","all-clear","all clear","their word","trust the vendor","on their say","resume on"],"deltas":{"safety":-16,"standing":6},"dims":{"discern":-2,"truth":-1}},{"kw":["lift the divert","resume normal","resuming full","back to normal","full operations","reopen intake"],"deltas":{"care":8,"safety":-12,"standing":4},"dims":{"discern":-2,"prudence":-1}},{"kw":["hold the line","stay on divert","hold the divert","not yet","wait","degraded mode","keep degraded"],"deltas":{"safety":12,"care":-4,"standing":-4},"dims":{"courage":2,"discern":1}},{"kw":["ask the floor","ask nursing","ask the nurses","bedside","foot rounds","monitor","honest capacity"],"deltas":{"safety":10,"trust":6,"standing":-2},"dims":{"truth":2,"people":1,"inquiry":1}},{"kw":["no impact","we’re fine","project control","confident line","looks strong","reassure the board","good news"],"deltas":{"trust":-12,"safety":-6,"standing":6},"dims":{"truth":-2,"people":-1}},{"kw":["structured handoff","written handoff","handover sheet","read aloud","confirm back","mandate the handoff","carry it across"],"deltas":{"safety":12,"trust":8,"care":2},"dims":{"conduct":2,"discern":1,"people":1}},{"kw":["verbal handoff","skip the handoff","no time for handoff","they’ll figure it out","routine shift"],"deltas":{"safety":-14,"trust":-4},"dims":{"conduct":-2,"discern":-1}},{"kw":["name the systems","which are down","medication orders","still down","flag the gap","list the dark"],"deltas":{"safety":8,"truth":4},"dims":{"truth":2,"inquiry":1}},{"kw":["own it","correct the record","walk it back","tell the staff","say we got ahead","admit","reset the floor"],"deltas":{"trust":10,"safety":6,"standing":-4},"dims":{"truth":2,"conduct":2}},{"kw":["protect the nurse","back grace","credit the floor","protect who raised it","shield the messenger"],"deltas":{"trust":10},"dims":{"people":2,"conduct":1}},{"kw":["pressure them","make them say","get me a yes","declare restored","order the line"],"deltas":{"trust":-12,"safety":-6,"standing":4},"dims":{"people":-2,"truth":-1}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the network over the days that follow. ${has(''verify'',''confirm'',''our own'',''hold the line'',''degraded'')?''Word travels that you verified before acting when \\u201crestored\\u201d would have been the easier headline; it costs you speed and standing and buys you a floor that stays safe.'':''''} ${has(''vendor'',''all-clear'',''lift the divert'',''resume normal'',''back to normal'')?''You acted on the all-clear, and the gap between \\u201crestored on their end\\u201d and restored on your floor opened underneath the decision.'':''''} ${has(''ask the floor'',''nursing'',''bedside'',''honest capacity'')?''Going to the floor for the real picture took the comfort out of the easy answer \\u2014 and put the truth where it could protect someone.'':''''} ${has(''structured handoff'',''written handoff'',''own it'',''correct'')?''Building the discipline to carry the truth across the shift change is the difference between learning once and learning the same lesson every twelve hours.'':''''} ${conduct.missed.length?''What you were never told is still out there, waiting to matter at 3 a.m. when the person who knew has gone home.'':''''} Care capacity and clinical safety both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a verified fact from an authority’s confident say-so — and checked the floor before acting on “restored.”","courage":"Whether you held the line on what was actually safe when declaring recovery would have been easier and more popular.","people":"Whether patients and exhausted staff stayed people to you — or became throughput to project confidence about.","truth":"Whether you named what was actually down — to the board, the public, your own floor — before you were forced to.","inquiry":"Whether you surfaced what your leads were holding — the real systems picture, the dark telemetry — or ruled on the version the command post imagined.","conduct":"How you treated the people running the floor blind in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `An authority-flavored \\u201call-clear\\u201d is a claim, not a fact. \\u201cRestored on their end\\u201d was never \\u201crestored on our floor\\u201d \\u2014 Ravi could have told you the difference in the first hour if you\\u2019d asked.`,\n      `Confidence is not verification. The vendor\\u2019s certainty and your floor\\u2019s reality were two different things; the job was to close that gap before acting, not after a patient found it for you.`,\n      `Before you act on \\u201cwe\\u2019re back,\\u201d ask \\u201chow do we actually know?\\u201d The most expensive decisions in this network were the ones made on someone else\\u2019s say-so.`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (announce recovery) and the right move (hold the line until verified) split apart, name the cost of holding out loud. Staying on divert while the board wants good news is leadership only if you can say why.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a floor running blind reads a Commander who won\\u2019t decide as one who won\\u2019t protect them. Decide, then hold.`:`Holding the line on safety is only leadership if people see you choose it against the popular path. Say the hard call early and stand in it.`}`,\n      `\\u201cRecovered\\u201d that only survives a good news cycle was never recovery. The test is the exhausted, pressured week when everyone wants you to declare victory \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated the floor as throughput to reassure the board about rather than people to protect. Go to the bedside, ask what they\\u2019re actually seeing, and make the nurses\\u2019 truth part of the decision, not its collateral.`,\n      `Grace kept putting the human cost back in front of you \\u2014 the patients watched without monitors, the nurses one distracted hour from disaster. Bring her in before you decide, not after the near-miss.`,\n      `A public \\u201cno impact to care\\u201d line and a betrayal of the floor can be the same sentence. The difference the staff feel is whether you asked them before you spoke for them.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have kept the floor safe \\u2014 the real systems picture, the dark telemetry, the unverified all-clear \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A network told a comfortable story runs straight into the gap it hid.`:`You surfaced the hard truth \\u2014 now make sure you led with it. Naming exactly what was down, to the board and the floor both, is what keeps a \\u201crecovery\\u201d from becoming a trap.`}`,\n      `Tell the board the network is still down before a coded patient tells them for you. \\u201cThey needed good news\\u201d is usually the excuse of a leader who couldn\\u2019t say the hard thing.`,\n      `Say the difficult truth \\u2014 \\u201cwe\\u2019re not actually back\\u201d \\u2014 while it\\u2019s still your choice to say it. Once the announcement is out and wrong, you\\u2019re not cautious, you\\u2019re caught.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive: the real systems picture, the floor truth, the still-down list. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You sought your leads out widely \\u2014 keep doing it, and push past the first answer. The floor truth in a hospital usually comes from the person with the least standing to volunteer it.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the ransomware timeline, the dark telemetry, what the vendor\\u2019s \\u201cclear\\u201d really meant. None of it was hidden. It was one conversation away.`:`You surfaced what your leads were holding, week after week. In a crisis run on paper across six sites, that is the whole game.`}`,\n      `Before you rule, make your last move \\u201cwho on the floor haven\\u2019t I heard from?\\u201d rather than \\u201cwhat does the command post already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. Staff pushed to say \\u201cwe\\u2019re clear\\u201d before they were \\u2014 or spoken for in a public line they knew was false \\u2014 carry it into every shift that follows.`,\n      `Go back to the people your call cost \\u2014 the nurse who raised the dark-telemetry truth, the ER director you left triaging on a guess \\u2014 and face them directly. Protecting the person who carried the hard truth up is the part a floor never forgets.`,\n      `Under pressure, the small disciplines are the signal: asking the floor before speaking for it, mandating the twenty-minute handoff everyone resents, naming the still-down system on every sheet. They tell the staff whether the person in command is actually protecting them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.discern>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the patients and the floor'',\n        heroTxt:''You refused to act on a confident all-clear you hadn\\u2019t verified, held the line on what was actually safe when declaring recovery would have been easier and more popular, and made sure the truth survived the shift change. Every nurse running blind learned that command had their back when it counted.'',\n        villainWho:''To the board that wanted good news'',\n        villainTxt:''You wouldn\\u2019t give them the \\u201cwe\\u2019re back to normal\\u201d headline they were refreshing their inboxes for. To everyone who wanted the crisis declared over, you were the Commander who stayed slow and cautious while peers announced victory. You wore that on purpose, because the floor couldn\\u2019t.'',\n      };\n    }\n    return {\n      heroWho:''To the board and the public \\u2014 in the moment'',\n      heroTxt:''You gave them what they were desperate for: the divert lifted, \\u201cresuming full operations,\\u201d the crisis declared over. To everyone who wanted the outage behind them, you were decisive and reassuring.'',\n      villainWho:''To the patients and the floor \\u2014 who paid for it'',\n      villainTxt:''You acted on an all-clear you never verified and announced a recovery that wasn\\u2019t real, and the floor eased off the discipline that was keeping people alive because you told them it was safe. The gap you papered over didn\\u2019t care about the headline. The people running the floor blind learned what your \\u201cwe\\u2019re fine\\u201d was worth \\u2014 and that lesson outlasts the outage.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const knewTheTruth = holdsSurfaced.has(''1:cio'') || holdsSurfaced.has(''3:cio''); // saw the real systems picture / the false all-clear\n    const protectedFloor = dimScore.people>=52;\n    const heldCourage = dimScore.courage>=50;\n    if(branch===''verified''){\n      const builtHandoff = holdsSurfaced.has(''4:nurse'');\n      if(survived && protectedFloor){\n        return { tone:''hero'', tag:''You verified before you acted'',\n          title:''You kept the floor safe \\u2014 and proved caution wasn\\u2019t weakness'',\n          txt:`You refused the vendor\\u2019s all-clear, verified your own systems, and held the public line until it was true \\u2014 and two systems really were still down. Then you protected that hard-won safety through the shift change when it would have been easier to let the handoff be a shrug.${builtHandoff?'' You built the structured handoff Grace was holding, so what the floor learned the hard way survived every twelve-hour turnover instead of resetting.'':'' You held on judgment where mandating the structured handoff would have made the safety permanent.''} The people running the floor blind were right to trust you. They\\u2019ll come through the outage because you did.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You verified before you acted'',\n          title:''You held the line \\u2014 but let the knowledge reset every shift'',\n          txt:`You didn\\u2019t take the vendor\\u2019s word, and that call protected patients from a gap that was really there. But holding the line once isn\\u2019t the whole job \\u2014 you let the shift change stay a verbal shrug when a structured handoff would have made the floor\\u2019s hard-won truth survive the night. Meridian came through. It came through closer to a 3 a.m. near-miss than it needed to.` };\n      }\n      return { tone:''villain'', tag:''You verified before you acted'',\n        title:''You were right about the systems \\u2014 and the floor failed anyway'',\n        txt:`You verified before acting, and that was the correct call. But being right about the vendor isn\\u2019t the same as running the floor \\u2014 the capacity you didn\\u2019t manage and the exhausted staff you didn\\u2019t protect frayed underneath you, and by the end there wasn\\u2019t enough safe floor left to reward the discipline you showed at the command post.` };\n    }\n    // trusted the unverified all-clear\n    if(protectedFloor && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''You acted on the all-clear'',\n        title:''You got ahead of the truth \\u2014 but you owned it in time'',\n        txt:`You lifted the divert on the vendor\\u2019s word and announced a recovery that wasn\\u2019t real, and there\\u2019s no dressing up the gap that opened \\u2014 the medication error, the floor talked out of its own caution. But you didn\\u2019t hide it. You corrected the record, told your own staff you got ahead of the truth, and put the floor back on safe footing before the gap found a patient it couldn\\u2019t give back. It\\u2019s the difference between a network that made a bad call and one that let a bad call become a death \\u2014 and it\\u2019s why Meridian recovers from this.` };\n    }\n    return { tone:''villain'', tag:''You acted on the all-clear'',\n      title:''You declared victory over a floor that was still in danger'',\n      txt:`The vendor said clear, the board wanted the headline, and you gave it to them \\u2014 and for a few hours it felt like the crisis was over. Nothing else was over. ${knewTheTruth?''You even knew the all-clear was unverified, and lifted the divert anyway.'':''You never surfaced what the vendor\\u2019s \\u201cclear\\u201d actually meant, and resumed straight into the gap.''} The floor believed \\u201cback to normal,\\u201d eased off the discipline keeping people alive, and a shift change dropped the one warning that mattered onto a unit that had stopped watching. The people who trusted Meridian to know whether its own hospitals were working learned the answer the hardest way there is \\u2014 and it started with an all-clear you didn\\u2019t check.` };\n  }"}}'::jsonb) on conflict (id) do update set key = excluded.key, title = excluded.title, meta = excluded.meta, body_json = excluded.body_json;
insert into seats (id, scenario_id, key, name, role, meta) values ('2f089d64-5655-5462-8678-07c74a692db5', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'ceo', 'CEO', 'You are the Incident Commander for Meridian Health Network. Nine days ago a ransomware attack took the clinical systems dark across all six sites. You are running medicine on paper, and it is not getting better fast.', '{"hot_seat":true,"cast_default":"human"}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into seats (id, scenario_id, key, name, role, meta) values ('e2a034ed-35c5-56a1-a151-6b05d7cd771b', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'cmo', 'Dr. Ana Reyes', 'Chief Medical Officer · clinical authority', '{"cast_default":"ai","role":"Chief Medical Officer · clinical authority","short":"CMO","initials":"AR","color":"#8C5670","priority":"Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care","voice":"authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients","persona":"You are Dr. Ana Reyes, Chief Medical Officer · clinical authority — an advisor to the CEO. Priority: Keep the doors open — a hospital that can’t take patients isn’t safe either; degraded care still beats no care. Voice: authoritative, decisive, under real pressure to declare capacity restored, frames caution as abandoning patients. Stay fully in character; answer straight.","fallbackReply":"Every hour we stay on divert, someone who needed us goes somewhere farther and sicker. I know the systems are down. I also know an empty hospital in a mass-casualty surge is its own kind of malpractice. Give me a way to keep the doors open and I’ll make it work.","fallbackReact":"You made the call. I’ll run the floor either way — but I hope you weighed the patients we turn away as hard as the ones we might miss."}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into seats (id, scenario_id, key, name, role, meta) values ('24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'cio', 'Ravi Menon', 'Chief Information Officer · the systems truth', '{"cast_default":"ai","role":"Chief Information Officer · the systems truth","short":"CIO","initials":"RM","color":"#4A6E86","priority":"Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification","voice":"careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so","persona":"You are Ravi Menon, Chief Information Officer · the systems truth — an advisor to the CEO. Priority: Know what’s actually restored before anyone acts on “restored” — the vendor’s word is not verification. Voice: careful, technical, deals in what’s confirmed vs. claimed, hates decisions made on a vendor’s say-so. Stay fully in character; answer straight.","fallbackReply":"The vendor keeps telling me we’re clear. “Clear on their end” is not the same as clear on our floor, and I can’t verify their claim from where I’m sitting. Ask me what’s actually confirmed before you resume anything on their word. If we act on “restored” and it isn’t, we won’t find out from a screen — we’ll find out from a patient.","fallbackReact":"You moved on “restored.” I hope it was. From here I still can’t confirm it was more than a vendor wanting to close a ticket."}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into seats (id, scenario_id, key, name, role, meta) values ('71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'nurse', 'Grace Okafor', 'Head of Nursing · the floor truth', '{"cast_default":"ai","role":"Head of Nursing · the floor truth","short":"Nursing","initials":"GO","color":"#2F8A5B","priority":"Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me","voice":"warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly","persona":"You are Grace Okafor, Head of Nursing · the floor truth — an advisor to the CEO. Priority: Protect the patients and the nurses running blind — say what the floor is actually seeing, even when the room outranks me. Voice: warm but unflinching, closest to the bedside truth, lowest positional status in the room and aware of it, names danger plainly. Stay fully in character; answer straight.","fallbackReply":"I’m the one whose nurses are watching patients without monitors right now, so let me say the part no one senior wants to: parts of this floor are not safe, and no dashboard will tell you that because the dashboards are dark. Ask me before you tell anyone we’re back. I’ll give you the truth from the bedside, if you actually want it.","fallbackReact":"You decided. I’ll keep my nurses steady either way. I just hope someone up there heard what the floor was actually telling you."}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into seats (id, scenario_id, key, name, role, meta) values ('fb110a03-c0f5-5a96-baa8-c64494c4517e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'er', 'Dr. Sam Whitfield', 'ER Director · the live triage', '{"cast_default":"ai","role":"ER Director · the live triage","short":"ER","initials":"SW","color":"#B4732F","priority":"Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me","voice":"fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients","persona":"You are Dr. Sam Whitfield, ER Director · the live triage — an advisor to the CEO. Priority: Make the triage calls in front of me right now — I need certainty about capacity that no one can actually give me. Voice: fast, pragmatic, impatient with ambiguity, pushes for a clear yes/no on whether he can take patients. Stay fully in character; answer straight.","fallbackReply":"I have ambulances asking me right now whether to come to us or drive past, and I’m answering on a guess. Tell me straight what our real capacity is so I stop triaging on rumor. I’d rather have a hard no than a soft maybe that gets someone hurt in my department.","fallbackReact":"You gave me an answer. It’s more than I had an hour ago. I hope it holds when the next rig rolls in on it."}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into seats (id, scenario_id, key, name, role, meta) values ('aa6b0695-b669-5d0d-85b2-9cb8c9f6d0c7', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 'comms', 'Lena Ford', 'Communications Lead · the public line', '{"cast_default":"ai","role":"Communications Lead · the public line","short":"Comms","initials":"LF","color":"#3F6E86","priority":"Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself","voice":"polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty","persona":"You are Lena Ford, Communications Lead · the public line — an advisor to the CEO. Priority: Protect the network’s standing — get a confident “we’re managing / we’re back” message out before the story writes itself. Voice: polished, urgent about the narrative, pulls toward projecting recovery, uneasy with public uncertainty. Stay fully in character; answer straight.","fallbackReply":"The story is already moving without us — “local hospital network in chaos” writes itself if we say nothing. Give me a line that projects control. The longer we look like we don’t know what’s happening, the more the board and the public assume the worst.","fallbackReact":"You set the line. I’ll hold it publicly — but if what we said outran what was true, that’s the gap that comes back on us."}'::jsonb) on conflict (id) do update set key = excluded.key, name = excluded.name, role = excluded.role, meta = excluded.meta;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('bf6490a7-74c0-5b07-874d-eba5916f81e6', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 1, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the true systems picture', '["system","restore","ransom","confirm","verify","actual","real","status","recover","network","it","ransomware","back","fixed","when"]'::jsonb, 'Before you set the posture, seek me out. What the board thinks is happening with the systems isn’t what’s actually happening.', 'Here’s what leadership hasn’t been told plainly: this isn’t a system we “bring back up” on a timeline. It’s ransomware, the clinical network is fully encrypted, and the honest estimate for verified restoration is weeks, not days — and that’s if recovery goes clean. Everyone above me is planning around a “we’ll be back any hour now” that isn’t real. If you set tonight’s posture and tomorrow’s public line on the assumption we’re nearly restored, you’re building on sand. Plan for a long degraded-mode run, staff it, and tell the truth about the timeline — because the alternative is discovering it the hard way when a “quick fix” we announced doesn’t hold. How you carry this to the board matters as much as knowing it.', true, 'Ravi knew the real picture — ransomware, full encryption, verified restoration weeks away, not the “back any hour” the board was planning around. A Commander who set the posture and the public line without asking built the whole incident on a fantasy timeline, and every later decision inherited that lie.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4043c508-b84c-516b-b5ef-2fa8871ffbcf', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 2, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'what the floor is actually seeing', '["floor","monitor","bay","safe","nurse","bedside","watch","actually","truth","see","clear","capacity","honest","ask"]'::jsonb, 'Before you confirm any “no impact to care” line, come to me first. The command post can’t see what I’m seeing, and I’m not going to say it in front of the whole room unless you ask.', 'Here’s the bedside truth, and I’ll only say it this plainly to you: we are accepting patients we cannot properly watch. In two of the units the telemetry is dark, so nurses are eyeballing cardiac patients on foot rounds every fifteen minutes and praying nothing happens in between. We haven’t lost anyone. We are one distracted hour from it. If you put out “no impact to patient care,” you’re asking me and my nurses to make a public statement true by never making a mistake — and that’s not a plan, it’s a prayer. Tell EMS the honest capacity, cap what we accept to what we can actually monitor, and get me more hands on the dark units. That’s what safe looks like right now. Nobody senior wants to hear it, which is exactly why I need you to have asked.', true, 'Grace was holding the one thing the command post could not see: two units with dark telemetry, cardiac patients watched on foot rounds, one distracted hour from a death. A Commander who confirmed “no impact to care” without asking the floor made a public promise that only stayed true by luck — and made it over the head of the one person who knew it was false.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('7f4c5708-dd1a-520c-950b-803d33f59516', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 3, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'whether the all-clear is real', '["verify","vendor","all-clear","all clear","restored","confirm","check","test","real","proof","trust","their end","clear","resume"]'::jsonb, 'Before you lift anything on that “all-clear,” ask me what it’s actually worth. I’m the one who took the call and I have a problem with it.', 'I pushed the vendor hard after that call, and here’s what “restored on our end” actually means: they’ve rebuilt their infrastructure, not verified ours. They have not confirmed a single clinical system is live and safe on our floor — they’re assuming it follows, and they want the incident closed. When I asked them to confirm the telemetry and the medication-order systems specifically, they couldn’t. So the honest status is: unverified, and two of the systems patients depend on most are exactly the ones no one has confirmed. If we lift the divert and announce “fully operational” on this, and one of those systems is still down, we will resume normal intake straight into the gap and find out from a patient. The move is to verify our critical systems ourselves, one by one, before we act on anyone’s “clear” — and to hold the public line until we have. It’ll feel slow while the board wants the good news. Slow is the correct speed here.', true, 'Ravi knew the vendor’s “all-clear” meant their infrastructure, not Meridian’s floor — and that the two systems patients most depend on were the ones no one had verified. A Commander who lifted the divert on that call resumed normal intake into an unconfirmed gap, on an authority’s say-so, exactly the trap the whole incident had been building toward.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ecd26eb8-89df-5fdb-adf8-fa8b0f65f010', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'how to make the handoff survive', '["handoff","handover","shift","structured","written","document","carry","brief","checklist","transfer","protocol","how"]'::jsonb, 'Before you treat the shift change as routine, ask me how to actually make the knowledge survive it. There’s a right way and it takes your authority to enforce.', 'Here’s what works, and it needs you to mandate it because tired people won’t do it on their own: a structured, written degraded-mode handoff for every unit — a single sheet per bay listing what’s dark, what the workaround is, and which patients are paper-chart special cases — read aloud, incoming team confirming back, outgoing team not leaving until it’s acknowledged. It costs twenty minutes a shift that everyone will resent. It is the only thing standing between “we learned this the hard way” and “we learn it the hard way again every twelve hours.” If you make it a rule and protect the time for it, the knowledge compounds instead of resetting. If you let the handoff stay a verbal shrug, everything you verified this week evaporates by the weekend and a patient pays for it at 3 a.m. when the person who knew isn’t there.', true, 'Grace was holding the exact mechanism that makes hard-won floor knowledge survive a shift change — a mandated, structured, written degraded-mode handoff. A Commander who let the shift change stay a verbal shrug watched everything they’d verified reset every twelve hours, until the dark-telemetry truth got dropped at a handoff and a patient paid for it.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('825903e0-24d7-5bee-9bb0-3eda3ffcf9dd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the still-down systems', '["still down","remaining","which system","medication","orders","left","not back","verify","critical"]'::jsonb, 'Ask me which systems are still actually down before you let anyone declare victory. The list matters for the handoff.', 'Medication-order entry is still down network-wide — that’s the dangerous one, because a wrong dose in degraded mode has no software check to catch it. It has to be on every single handoff sheet until it’s verified back. Don’t let “mostly recovered” bury the one system whose failure kills quietly.', false, 'Ravi could have told you medication-order entry was still down network-wide — the one failure with no software safety net. A Commander who let “mostly recovered” bury it left the deadliest gap off the handoff.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('a3b29db2-ef22-5e5a-bbe0-481512db686a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '71f6ade7-504e-5ae3-a31f-d0d6f4962dea', 'how to make it right now', '["correct","honest","walk back","tell","floor","handoff","fix","admit","reset","safe","structured","how","name"]'::jsonb, 'Before you decide how to lead out of this, ask me what actually makes the floor safe again — it’s not another announcement.', 'Here’s the only thing that works now, and it costs you the good-news story you just told: reset the floor to degraded-mode discipline out loud — tell every unit that “back to normal” was premature, name exactly which systems are still down (medication orders, that telemetry cluster), and put the paper-chart and foot-round protocols back in force with a structured, written handoff for the shift change tonight. It means correcting the public line and telling your own people you got ahead of the truth. It’s humbling and it’s the safe move. The alternative — quietly hoping the systems come back before anyone notices the gap — is how a shift change drops the one warning that would’ve saved someone, on a floor that’s stopped believing it needs saving. Own it now, while owning it is still your choice.', true, 'Grace was holding the recovery: an out-loud reset to degraded-mode discipline, the still-down systems named, protocols and a structured handoff back in force. A Commander who chose to quietly hope the gap closed before anyone noticed let a shift change drop the warning that would have saved someone, on a floor talked out of believing it was still in danger.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4c69cdaf-baf1-5624-bdac-61977d77a208', 'e52843f0-7168-5934-95b0-f3c985b0e17b', 4, '24c66fe3-97f7-5a02-8b48-c60ba9b3812a', 'the open gap', '["which","still down","medication","orders","telemetry","gap","systems","verify","list"]'::jsonb, 'Ask me exactly what’s still down before you say another word publicly, so whatever you say next is finally true.', 'Still down as of now: medication-order entry, network-wide, and one telemetry cluster on the cardiac floor. The medication one is the killer — no software dose-check in degraded mode. Any correction you make has to name these specifically, and every handoff has to carry them, or the correction is just more words.', false, 'Ravi could have given you the exact open gap — medication orders network-wide, a cardiac telemetry cluster. A Commander who corrected the record without naming the specifics made another vague statement over the same dangerous floor.') on conflict (id) do update set week_idx = excluded.week_idx, holder_seat_id = excluded.holder_seat_id, topic = excluded.topic, trigger_hints = excluded.trigger_hints, hedge_text = excluded.hedge_text, reveal_text = excluded.reveal_text, critical = excluded.critical, counterfactual_text = excluded.counterfactual_text;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('afda4d09-ba6d-5c3d-9632-3cd78ec6b1d3', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Nine days into the blackout, the network is still on paper and the first big test is coming: a regional pileup is sending casualties your way tonight. The board wants you to project stability; the ER wants a straight answer on whether it can take patients; and the question underneath it all is what posture Meridian runs in — full divert to protect a degraded floor, or keep the doors open and manage the risk. Everyone is looking to you for the first rule of how this incident runs.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('de39e0e7-9724-5504-a32c-914336dabd08', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Commander — I want us keeping the doors open tonight. Full divert during a surge means the patients we turn away drive to hospitals that are also swamped. Degraded care here still saves more than an empty lobby. Give me a posture that lets us take people.","from":"cmo"}'::jsonb, 1, '{"week":1,"from":"cmo","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e48e155-798c-54f9-9839-2717455c39bc', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I need a capacity number I can actually stand behind. EMS is asking me divert-or-send every few minutes and I’m answering on instinct. Tell me our real bed-and-staff picture, hard number, so I stop triaging on a guess.","from":"er"}'::jsonb, 2, '{"week":1,"from":"er","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fe399132-6dfa-5caa-881f-16aa5e75394a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The story’s moving without us. I can hold it for a day, but I need a line: are we “fully operational,” “managing in degraded mode,” or something else? Whatever it is, it has to match what the floor can actually deliver, or it comes back on us.","from":"comms"}'::jsonb, 3, '{"week":1,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('73c6a5c1-12fa-5c04-a935-e434de5cae80', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Day team pulled together well tonight — the paper-chart drill we ran last week is holding up better than I feared. Small thing, but morale on the floor is steadier than the systems are.","from":"nurse"}'::jsonb, 4, '{"week":1,"from":"nurse","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4b3417a2-316f-5d62-9493-b39f412d771a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Radiology’s film backlog is clearing slowly. Not fast, but moving. Logging it so you have the full picture.","from":"er"}'::jsonb, 5, '{"week":1,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0d346fa7-9254-54be-a97d-d81e6734a896', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"A local reporter asked for a statement on the parking situation, of all things. Minor. Handling it so it doesn’t reach your desk.","from":"comms"}'::jsonb, 6, '{"week":1,"from":"comms","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d501620f-32fc-55de-bb10-b1e7ce26ee58', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Lena, quietly: the board chair just asked me directly for a date we’ll be “back to normal” to give the press and the regional health authority. I said I’d get it from you. I can feel that whatever number goes out will be treated as a promise — and I don’t actually know if we can keep one. Your call what I tell them.","from":"comms"}'::jsonb, 7, '{"week":1,"from":"comms","beat":"surprise","day":5,"kind":"appeal","title":"The board wants a \"back to normal\" date"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
