insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('06a08092-8e0f-5e75-8339-516c3bc0beed', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"The casualties came. The floor is full, the staff are stretched thin running blind on paper, and the pressure now is to tell everyone — the board, EMS, the public — that Meridian is coping better than it is. The ER wants to keep taking patients because turning them away feels like failing. But somewhere on the floor, the truth about what’s actually safe is being carried by the person with the least standing to say it in your command post.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('90f4505e-4236-5184-808e-ed62f43aa4a5', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"We took the surge and we’re standing. I want to keep the doors wide — every wave-off is a patient driving past us bleeding. Give me the green light to keep accepting and I’ll keep finding room.","from":"er"}'::jsonb, 13, '{"week":2,"from":"er","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('07782d33-c346-5360-818a-8553e042a7ea', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I’ve got a strong line ready: “Meridian is managing the surge with no impact to patient care.” The board loves it. But I’m not sending it until you confirm it’s actually true — because if it isn’t, that sentence is the one that ends up in the inquiry.","from":"comms"}'::jsonb, 14, '{"week":2,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8842703b-c73a-58bf-a881-9f03031e32e2', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The floor is performing, but “performing” and “safe” aren’t the same word. Before we tell EMS we’re wide open, I want to be sure we can actually monitor the patients we’re saying yes to. Ask the floor, not the command post.","from":"cmo"}'::jsonb, 15, '{"week":2,"from":"cmo","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4996a0ba-e578-5ba6-826f-e30827510c66', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"National desk picked up the regional story but the framing is neutral so far — “hospitals respond to outage.” Manageable. Watching it.","from":"comms"}'::jsonb, 16, '{"week":2,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2aecb5b2-05ad-5229-a6ba-1b501312eb20', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Second ambulance bay opened back up after we cleared the film backlog. Bit more breathing room. Logging it.","from":"er"}'::jsonb, 17, '{"week":2,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('553803f6-91d7-5998-a60a-a4d7c0b02362', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Sam, urgent: EMS dispatch needs a firm capacity number in the next hour to route the second wave, and the honest answer depends on whether we can actually monitor who we accept. I can give them an optimistic number that keeps us looking strong, or a real one that sends some patients elsewhere. I need to know which Meridian you want me to be before I key the radio.","from":"er"}'::jsonb, 18, '{"week":2,"from":"er","beat":"surprise","day":4,"kind":"appeal","title":"EMS wants a hard capacity number now"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5be736b2-de7e-54ea-847d-ee692cd8ef97', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace catches you in the corridor, away from the command post, her voice low: “Before you tell anyone out there that we’re fine — tell me, just me: do you actually believe this floor is safe right now, or do you need it to be because ‘safe’ is the easier thing to announce? Because I’ll stand beside a Commander who tells the hard truth about my floor. I won’t cover for one who tells a comfortable one. Which are you about to be?”","from":"nurse"}'::jsonb, 19, '{"week":2,"from":"nurse","beat":"pulse"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
