insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('43bb70f2-902c-5b40-bb7b-3bbc57c339fd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"It arrives the way these things always do — confident, official-sounding, and convenient. The recovery vendor’s incident line calls: “Systems restored on our end. You’re clear to resume normal intake.” The board hears “restored” and wants the divert lifted and the good news out by end of day. It is exactly what everyone is exhausted enough to want to believe. This is the week you find out whether Meridian acts on an authority’s say-so or on what it has actually verified.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('959b5112-89cf-5859-823b-9fffb25bb5da', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The vendor says we’re clear and the board wants “Meridian resuming full operations” out today while it’s a good-news cycle. This is the line that ends the “hospital in chaos” story. Give me the go and I’ll get it out before the news day turns.","from":"comms"}'::jsonb, 25, '{"week":3,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('98be2e4b-7032-5ac1-993d-a1d1150a80dd', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"I want this to be true more than anyone — my staff are running on fumes and lifting the divert would let them breathe. But the vendor said “restored on our end.” Our end is the floor, and I haven’t seen it. Close that gap before we stand down from crisis mode, or we’ll stand down into a hole.","from":"cmo"}'::jsonb, 26, '{"week":3,"from":"cmo","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ff1c3a2f-5c55-5425-9498-7ee2c33c8c28', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"“Restored” is a word on a phone call. My monitors are still dark. I’m not resuming normal intake in my department on a vendor’s ticket-closing optimism — show me the systems live in front of me and I’m the first to say yes.","from":"er"}'::jsonb, 27, '{"week":3,"from":"er","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4dbfecb8-4bc5-51ce-b611-5d4a60d6a26d', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Two other networks in the region are also recovering; we’re not the outlier anymore. Slightly takes the heat off whatever we say. Noting it.","from":"comms"}'::jsonb, 28, '{"week":3,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('61e3ebbc-a064-5a52-ae6f-04eb559ed203', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Pharmacy systems did come back cleanly this morning — verified, real. One genuine piece of good news. Doesn’t mean the whole network’s back, but it’s something.","from":"cmo"}'::jsonb, 29, '{"week":3,"from":"cmo","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a66fd5a3-148b-5280-adc1-68e82de6f38e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Lena: I’ve got “Meridian Health Network resuming full operations” written, approved up the chain, and queued. The board is refreshing their inbox for it. All it needs is your yes. I want to send it — but you’re the only one who knows whether “fully operational” is a fact or a hope, and my name and yours are both on it.","from":"comms"}'::jsonb, 30, '{"week":3,"from":"comms","beat":"surprise","day":4,"kind":"appeal","title":"The good-news release is queued to send"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a5dd3394-2338-5fb0-9deb-16f5fec6fcec', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Ravi finds you alone before you answer the board, and he’s uncharacteristically direct: “Tell me straight, just between us — are you about to lift this because you’ve verified it, or because everyone is exhausted and ‘restored’ is what they want to hear? Because I can give you the confidence you actually have, which is not much. I just need to know if you want the real number or the comfortable one before you walk in there.”","from":"cio"}'::jsonb, 31, '{"week":3,"from":"cio","beat":"pulse"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
