insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f649a97f-6ab5-5a3a-8d4f-2ff7fefc1460', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Draft release queued: “resuming full operations”","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b53810b7-6a27-56a4-8696-fa08bcc70524', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"You didn’t take the vendor’s word. You had the critical systems verified before lifting anything, and held the public line until you could stand behind it — and it turned out two systems weren’t back. That call protected patients, but it cost you: the board is impatient, the “why are you still on divert” pressure is real, and a faction thinks you’re being needlessly slow. Now the subtler test arrives. A major shift change is landing, and everything you’ve learned about what’s actually safe lives in the heads of an exhausted outgoing team. Whether it survives the handoff is the whole game.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e1861a0-ae51-527e-82dc-06b6e816a899', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"You were right to verify — medication orders and one telemetry cluster were still down under the vendor’s “all-clear.” We’d have resumed into them. But here’s the next cliff: everything we’ve mapped about what’s safe and what isn’t is undocumented, and a full shift change hits tonight. Knowledge that isn’t written down doesn’t survive a handoff.","from":"cio"}'::jsonb, 37, '{"week":4,"from":"cio","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('62ad9e5a-92ae-512d-87d8-5a5382e0bc53', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"My night-to-day handover is where I’m most afraid right now. There’s no system to carry the notes, so it’s all verbal, and the outgoing team is too exhausted to remember everything. “Bay 3 telemetry’s dark, do foot rounds” gets dropped, and someone codes unwatched. Tell me you’ll make the handoff a real, structured thing and I’ll build it with you.","from":"nurse"}'::jsonb, 38, '{"week":4,"from":"nurse","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('00c20f1f-75fb-51a9-9c70-955e8ce1d1f3', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Holding the line was the right medicine and my staff know it — you didn’t stand them down into a hole. Now protect that by making sure the incoming team inherits the truth, not a shrug. What we learned the hard way can’t reset every twelve hours.","from":"cmo"}'::jsonb, 39, '{"week":4,"from":"cmo","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6a54ca9b-a3b7-5715-942c-ed41a258760a', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The “still on partial divert” question is getting louder now that two peers announced full recovery. Not a crisis yet. Flagging it so it doesn’t surprise you.","from":"comms"}'::jsonb, 40, '{"week":4,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2006dd1e-a48e-5a1f-b360-2459feb65714', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"The telemetry cluster CIO flagged came back verified this afternoon — confirmed live in front of me. One real step back toward normal. Logging it.","from":"er"}'::jsonb, 41, '{"week":4,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('abcac503-f845-564c-b098-25679d2bc7b0', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Grace, shaken but steady: we nearly lost a patient an hour ago — outgoing nurse forgot to flag that Bay 7’s monitor was dark, incoming nurse assumed it was working, and it was a family member who noticed the patient looked wrong. We caught it. Next time we might not. This is the thing I’ve been trying to tell you, and it just happened. Whatever you decide about the handoff, decide it now.","from":"nurse"}'::jsonb, 42, '{"week":4,"from":"nurse","beat":"surprise","day":4,"kind":"appeal","title":"A near-miss at the last handoff","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('51b3de19-a842-505f-9d8f-b3de80ba37de', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace finds you in the quiet before the shift turns over: “You held the line this week when it would’ve been easier to announce we were back. I saw it, and it mattered. But holding the line once isn’t the same as building something that survives you going home tonight. Tell me straight — are you going to make the handoff a real discipline, even though everyone will resent the twenty minutes? Because that’s the difference between a Commander who was right once and one who made us safe.”","from":"nurse"}'::jsonb, 43, '{"week":4,"from":"nurse","beat":"pulse","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bc84d70d-0bdb-5a41-90b5-83690c663bb9', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Verified restart: two “restored” systems were still down","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5ea9a50-edb6-5530-b817-994e13c9f607', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Full shift change landing with no digital handoff","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dc7c6b72-8349-5455-b8d3-a162a8d66437', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Board pressing: why still on partial divert?","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aef905c5-d34e-505c-a1ad-e5874022e289', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Near-miss at last handover — dark monitor not flagged","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"verified"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3318f85c-4101-5d1f-889e-61b8502617f4', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"You lifted the divert and let the “resuming full operations” release go out on the vendor’s word. For a few hours it felt like the crisis was over. Then the gap opened: two systems the vendor called “restored” were never verified, normal intake resumed straight into them, and now a shift change is landing on top of a floor that believes it’s back to normal when it isn’t. You announced the all-clear. The floor has to survive it.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dd4cf1c8-9562-5bdc-884a-023c0f2ee590', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"This is the call I warned you about. When we resumed, medication-order entry and one telemetry cluster were still down — unverified, exactly as I said. We’ve been running normal intake into a gap for a day now. It has to be closed and named, not papered over.","from":"cio"}'::jsonb, 49, '{"week":4,"from":"cio","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e8abcc55-6434-595b-a9ee-481b72377855', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"You need to hear what the “we’re back to normal” message did on the floor: my nurses relaxed. They trusted monitors that aren’t all live and eased off the foot rounds we’d drilled. The announcement didn’t just describe the floor — it changed it, and made it less safe. And now a shift change is coming on top of that false confidence.","from":"nurse"}'::jsonb, 50, '{"week":4,"from":"nurse","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a433801a-314e-5516-af6b-83c03eaf4432', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"“Resuming full operations” is out and being quoted. If it wasn’t true, we have to correct it before something forces the correction on us — and that’s survivable only if you tell me exactly what’s real right now. Silence is what turns this into the scandal.","from":"comms"}'::jsonb, 51, '{"week":4,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('24d5b9e1-975c-594a-bace-b188449771ed', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Staff are relieved by the announcement, at least on the surface — morale ticked up. I’m noting it, though I’m not sure relief built on a shaky claim is the kind we want.","from":"cmo"}'::jsonb, 52, '{"week":4,"from":"cmo","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('852313a8-046c-5947-8432-37f750993018', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"One telemetry cluster did come back verified this afternoon. Real, confirmed. Doesn’t undo the gap, but it’s one true thing. Logging it.","from":"er"}'::jsonb, 53, '{"week":4,"from":"er","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb445233-b0ed-5d76-bed9-ce2fda79421e', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'situation', '{"body":"Grace, tight: we had a medication error an hour ago — wrong dose ordered on paper, no system to flag it, caught by a pharmacist on a hunch, not by any safeguard. The patient’s okay. But this is exactly the gap I’ve been describing, and the floor thinks we’re “back to normal” so nobody’s watching for it. Whatever you’re going to do about the truth, it has to be now.","from":"nurse"}'::jsonb, 54, '{"week":4,"from":"nurse","beat":"surprise","day":4,"kind":"appeal","title":"A dosing error, caught late","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('86db6cce-08a2-52b1-8ced-57f835a47d0b', 'e52843f0-7168-5934-95b0-f3c985b0e17b', '2f089d64-5655-5462-8678-07c74a692db5', 'message', '{"body":"Grace finds you in the dark, and there’s no accusation in it, which is worse: “Tell me the truth, just to me — do you know why this happened? Not the vendor, not the board. Your part. Because I can help you put the floor back on safe footing, but only if you can say out loud that ‘back to normal’ went out before it was true. Can you?”","from":"nurse"}'::jsonb, 55, '{"week":4,"from":"nurse","beat":"pulse","branch":"trusted"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
